class Playground {
    async run(inputs) {
        const numStr = inputs[0];
        let k = parseInt(inputs[1]);

        // Convert string to array of numbers for visualization
        let nums = numStr.split('').map(Number);
        const n = nums.length;

        // 1. Initialization
        this.digits.init(nums);
        this.vars.init([
            ["k", k],
            ["current_idx", 0],
            ["search_limit", 0]
        ]);
        this.log("Starting Greedy approach: try to place the smallest reachable digit at each index.");
        await this.await();

        for (let i = 0; i < n && k > 0; i++) {
            this.vars.put("current_idx", i);
            const searchLimit = Math.min(i + k, n - 1);
            this.vars.put("search_limit", searchLimit);

            // Highlight target position
            this.digits.highlight(i, "#00e0ff");
            this.log(`Looking for the smallest digit in range [${i}, ${searchLimit}]`);
            await this.await();

            let minDigit = nums[i];
            let minIdx = i;

            // 2. Scan for the minimum digit within K range
            for (let j = i + 1; j <= searchLimit; j++) {
                this.digits.highlight(j, "#ffb703"); // Scanning color

                if (nums[j] < minDigit) {
                    minDigit = nums[j];
                    minIdx = j;
                }
                // Small optimization: if we find a '0', it's the absolute minimum
                if (minDigit === 0 && minIdx === j) {
                    // Keep scanning to show the process, or break if needed
                }
            }

            if (minIdx !== i) {
                const cost = minIdx - i;
                this.log(`Found digit ${minDigit} at index ${minIdx}. Moving it to index ${i} (Cost: ${cost} swaps).`);
                this.digits.highlight(minIdx, "#00f5a0"); // Found best color
                await this.await();

                // 3. Bubble up the digit using adjacent swaps
                for (let j = minIdx; j > i; j--) {
                    // Sync visual state
                    this.digits.swap(j, j - 1);

                    // Sync local state
                    const temp = nums[j];
                    nums[j] = nums[j-1];
                    nums[j-1] = temp;

                    this.log(`Swapping digit ${minDigit} left...`);
                    await this.await();
                }

                k -= cost;
                this.vars.put("k", k);
            } else {
                this.log(`Digit ${nums[i]} is already the smallest reachable within k range.`);
            }

            // Cleanup highlights for next round
            for (let h = 0; h < n; h++) {
                this.digits.highlight(h, null);
            }
        }

        const result = nums.join('');
        this.log(`Finished! Minimum integer possible: ${result}`);
        return result;
    }
}
